import re
from pathlib import Path

AC_UID = "fe85f20bacc04fef"
AC_TYPE = "data"

PUSH_MD = str(Path(__file__).parent.parent.parent.parent / "commands" / "push.md")


def test_AC8():
    """
    GIVEN: commands/push.md at HEAD
    WHEN:  grep "rm -f.*push-analyst" commands/push.md is run, AND grep for imperative orchestrator-directed phrases in Step 4 ("Read the grant at", "Validate the following", "Consume.*unlink") is run
    THEN:  "rm -f.*push-analyst" grep exits 1 (no such line remains) OR the only occurrence is inside a comment or historical reference; AND the Step 4 imperative phrases grep exits 1 (old instructions removed); AND grep for execute-push.py in Step 4 area returns a reference to the script
    """
    content = Path(PUSH_MD).read_text()
    lines = content.splitlines()

    # Check: no line matches "rm -f.*push-analyst" outside of comments or code blocks
    rm_pattern = re.compile(r"rm\s+-f.*push-analyst")
    rm_matches = [line for line in lines if rm_pattern.search(line)]
    # Filter out comment lines (start with # or >) and lines inside code blocks
    # For markdown, we consider lines starting with > as blockquotes (allowed historical refs)
    non_comment_rm = [
        line for line in rm_matches
        if not line.strip().startswith("#") and not line.strip().startswith(">")
    ]
    assert not non_comment_rm, (
        f"Found 'rm -f.*push-analyst' outside comments/blockquotes: {non_comment_rm}"
    )

    # Check: execute-push.py is referenced in the Step 4 or Step 5 area
    # Find Step 4 section
    step4_marker = "**Step 4:"
    step4_start = content.find(step4_marker)
    assert step4_start != -1, f"'**Step 4:' not found in {PUSH_MD}"

    # Extract from Step 4 to end of Step 5 (find Step 6 or ## as boundary)
    step4_text = content[step4_start:]
    # Find next top-level section or step 6
    next_section = re.search(r"\n(?:##|\*\*Step 6:)", step4_text)
    if next_section:
        step45_text = step4_text[:next_section.start()]
    else:
        step45_text = step4_text

    assert "execute-push.py" in step45_text, (
        f"'execute-push.py' not found in Step 4/5 area of {PUSH_MD}"
    )
